sql:
SELECT AVG(intensity) AS average_intensity
FROM quantification
WHERE quantification_method = 'label-free';

SELECT intensity
FROM quantification
WHERE quantification_method = 'TMT';

SELECT COUNT(*) 
FROM raw_data 
WHERE strftime('%Y-%m', upload_date) = '2023-01';

SELECT file_name, upload_date
FROM raw_data
WHERE sample_prep_method = 'FASP';

external_knowledge:
; Label-free quantification is a method in mass spectrometry that quantifies proteins without the need for isotope labeling, allowing for a more direct comparison of protein abundance across different samples; 
; 'Orbitrap' refers to a type of high-performance mass spectrometer known for its high resolution and mass accuracy, often used in proteomics research for the identification and quantification of proteins;
; 'MaxQuant' is a software suite for the analysis of high-resolution mass spectrometry data, specifically designed for the identification and quantification of proteins and their modifications.

